trigger.body:
	vDocTypeID		VARCHAR2(32);
	vCurrentNext	VARCHAR2(30);
	vSeq			RECORD;

BEGIN

	IF AD_isTriggerEnabled() = 'N' THEN RETURN;END IF;

	IF INSERTING THEN

		vDocTypeID := :NEW.EM_SSIMPDT_C_DocType_ID;    

		SELECT s.* INTO vSeq
		FROM ad_sequence s
			JOIN c_doctype dt ON dt.docnosequence_id = s.ad_sequence_id
		WHERE dt.c_doctype_id = vDocTypeID;

		vCurrentNext := vSeq.currentnext;
		IF vSeq.prefix IS NOT NULL THEN 
			vCurrentNext := vSeq.prefix||vCurrentNext;
		END IF;

		UPDATE C_Campaign SET EM_SSIMPDT_DocumentNo = vCurrentNext,
			value = REPLACE(value, :NEW.EM_SSIMPDT_DocumentNo, vCurrentNext),
			name = REPLACE(name, :NEW.EM_SSIMPDT_DocumentNo, vCurrentNext)
		WHERE C_Campaign_ID = :NEW.C_Campaign_ID;

		UPDATE ad_sequence SET currentnext = vSeq.currentnext + 1 
		WHERE ad_sequence_id = vSeq.AD_Sequence_ID;

	END IF;

	END SSIMPDT_CC_DOCUMENTNO_TRG
